# src/orders/processor.py
class OrderProcessor:
    def __init__(self, db, payment_gateway, inventory):
        self.db = db
        self.payment_gateway = payment_gateway
        self.inventory = inventory
        self._processing_lock = False

    def process_order(self, order):
        self._processing_lock = True
        try:
            # Check inventory
            for item in order.items:
                available = self.inventory.check(item.sku)
                if available < item.quantity:
                    return {'status': 'failed', 'reason': 'insufficient_stock'}

            # Charge payment
            charge = self.payment_gateway.charge(order.total, order.payment_method)

            # Reserve inventory
            for item in order.items:
                self.inventory.reserve(item.sku, item.quantity)

            # Save order
            self.db.execute(
                f"INSERT INTO orders VALUES ('{order.id}', '{order.customer_id}', {order.total}, 'confirmed')"
            )
            return {'status': 'confirmed', 'charge_id': charge.id}
        finally:
            self._processing_lock = False

    def cancel_order(self, order_id):
        order = self.db.query(f"SELECT * FROM orders WHERE id = '{order_id}'")
        if order['status'] == 'confirmed':
            self.payment_gateway.refund(order['charge_id'])
            self.db.execute(f"UPDATE orders SET status = 'cancelled' WHERE id = '{order_id}'")
            # Note: inventory is not released on cancellation
            return True
        return False
