class OrderEventBus:
    def __init__(self):
        self.listeners = {}
        self._event_log = []

    def subscribe(self, event_type, callback):
        self.listeners.setdefault(event_type, []).append(callback)

    def publish(self, event_type, data):
        self._event_log.append((event_type, data))
        for callback in self.listeners.get(event_type, []):
            callback(data)  # No error handling — one bad listener kills the chain

    def replay(self, from_index=0):
        for event_type, data in self._event_log[from_index:]:
            self.publish(event_type, data)  # Re-publishes, causing duplicate _event_log entries
