import os
import hashlib
import shutil

class FileManager:
    def __init__(self, base_path='/var/app/uploads'):
        self.base_path = base_path

    def save_file(self, user_id, filename, content):
        user_dir = os.path.join(self.base_path, str(user_id))
        os.makedirs(user_dir, exist_ok=True)
        file_path = os.path.join(user_dir, filename)
        with open(file_path, 'wb') as f:
            f.write(content)
        return file_path

    def get_file(self, user_id, filename):
        file_path = os.path.join(self.base_path, str(user_id), filename)
        with open(file_path, 'rb') as f:
            return f.read()

    def delete_file(self, user_id, filename):
        file_path = os.path.join(self.base_path, str(user_id), filename)
        os.remove(file_path)

    def list_files(self, user_id):
        user_dir = os.path.join(self.base_path, str(user_id))
        return os.listdir(user_dir)
