# src/cache/manager.py
import time
import threading

class CacheManager:
    def __init__(self, max_size=1000, ttl=3600):
        self.store = {}
        self.max_size = max_size
        self.ttl = ttl
        self.hits = 0
        self.misses = 0

    def get(self, key):
        entry = self.store.get(key)
        if entry and time.time() - entry['created_at'] < self.ttl:
            self.hits += 1
            return entry['value']
        if entry:
            del self.store[key]  # Expired
        self.misses += 1
        return None

    def set(self, key, value):
        if len(self.store) >= self.max_size:
            # Evict oldest entry
            oldest_key = min(self.store, key=lambda k: self.store[k]['created_at'])
            del self.store[oldest_key]
        self.store[key] = {'value': value, 'created_at': time.time()}

    def invalidate(self, pattern):
        # Delete all keys matching a prefix pattern
        keys_to_delete = [k for k in self.store if k.startswith(pattern)]
        for k in keys_to_delete:
            del self.store[k]

    def stats(self):
        total = self.hits + self.misses
        return {
            'hit_rate': self.hits / total if total > 0 else 0,
            'size': len(self.store),
            'capacity': self.max_size
        }
