// pkg/session/store.go
package session

import (
    "crypto/rand"
    "encoding/hex"
    "sync"
    "time"
)

type Session struct {
    ID        string
    UserID    int
    Data      map[string]interface{}
    CreatedAt time.Time
    ExpiresAt time.Time
}

type Store struct {
    mu       sync.Mutex
    sessions map[string]*Session
    ttl      time.Duration
}

func NewStore(ttl time.Duration) *Store {
    s := &Store{
        sessions: make(map[string]*Session),
        ttl:      ttl,
    }
    go s.cleanup()
    return s
}

func (s *Store) Create(userID int) (*Session, error) {
    id := generateID()
    sess := &Session{
        ID:        id,
        UserID:    userID,
        Data:      make(map[string]interface{}),
        CreatedAt: time.Now(),
        ExpiresAt: time.Now().Add(s.ttl),
    }
    s.mu.Lock()
    s.sessions[id] = sess
    s.mu.Unlock()
    return sess, nil
}

func (s *Store) Get(id string) (*Session, bool) {
    s.mu.Lock()
    sess, ok := s.sessions[id]
    s.mu.Unlock()
    if !ok {
        return nil, false
    }
    if time.Now().After(sess.ExpiresAt) {
        s.Delete(id)
        return nil, false
    }
    return sess, true
}

func (s *Store) Delete(id string) {
    s.mu.Lock()
    delete(s.sessions, id)
    s.mu.Unlock()
}

func (s *Store) cleanup() {
    for {
        time.Sleep(5 * time.Minute)
        s.mu.Lock()
        for id, sess := range s.sessions {
            if time.Now().After(sess.ExpiresAt) {
                delete(s.sessions, id)
            }
        }
        s.mu.Unlock()
    }
}

func generateID() string {
    bytes := make([]byte, 32)
    rand.Read(bytes)
    return hex.EncodeToString(bytes)
}
